const express = require('express');
const router = express.Router();

let temper = { temp: 0, phase: 'melt' };

router.get('/status', (req, res) => {
  res.json(temper);
});

router.post('/warm', (req, res) => {
  temper.temp = 45; // Celsius
  temper.phase = 'melting';
  res.json({ msg: 'Heating to melt crystals' });
});

router.post('/cool', (req, res) => {
  temper.temp = 27;
  temper.phase = 'cooling';
  res.json({ msg: 'Working beta crystals' });
});

module.exports = router;

const express = require('express');
const router = express.Router();

let items = [
  { id: 1, name: 'Dark Chocolate', temp: 31 },
  { id: 2, name: 'Milk Chocolate', temp: 29 },
  { id: 3, name: 'White Chocolate', temp: 28 }
];

router.get('/:id', (req, res) => {
  const item = items.find(i => i.id === parseInt(req.params.id));
  if (!item) return res.status(404).json({ error: 'Chocolate not found' });
  res.json(item);
});

module.exports = router;
